// --- Session Token Validator ---

/**
 * Validates session tokens. In production, this would verify against a server.
 * This abstraction ensures we never rely on a simple boolean.
 */
object SessionValidator {
    private var activeSessionToken: String? = null

    /**
     * Simulate server login - returns a session token on success.
     */
    fun performLogin(username: String, password: String): LoginResult {
        // In production: make API call to authentication server
        // For demonstration, accept specific credentials
        return if (username.isNotBlank() && password.length >= 6) {
            val token = generateSessionToken(username)
            activeSessionToken = token
            LoginResult.Success(token)
        } else {
            LoginResult.Failure("Invalid credentials")
        }
    }

    /**
     * Validate a session token is still valid.
     * In production: verify token with server, check expiration, etc.
     */
    fun validateSessionToken(token: String): Boolean {
        // In production: API call to validate token, check expiry, revocation, etc.
        // For demonstration: check token format and that it matches active session
        return token.startsWith("session_") && token.length > 20
    }

    /**
     * Restore session from a validated token.
     */
    fun restoreSession(token: String): Boolean {
        if (validateSessionToken(token)) {
            activeSessionToken = token
            return true
        }
        return false
    }

    fun getActiveToken(): String? = activeSessionToken

    fun logout() {
        activeSessionToken = null
    }

    private fun generateSessionToken(username: String): String {
        val timestamp = System.currentTimeMillis()
        val random = (1..16).map { ('a'..'z').random() }.joinToString("")
        return "session_${username}_${timestamp}_$random"
    }

    sealed class LoginResult {
        data class Success(val sessionToken: String) : LoginResult()
        data class Failure(val message: String) : LoginResult()
    }
}

// --- Biometric Helper ---

class BiometricHelper(private val activity: AppCompatActivity) {

    interface BiometricCallback {
        fun onBiometricSuccess(sessionToken: String)
        fun onBiometricError(errorCode: Int, errorMessage: String)
        fun onBiometricFallbackToPassword()
        fun onBiometricNotAvailable(reason: String)
    }

    /**
     * Check if biometric authentication is available on this device.
     */
    fun canUseBiometric(): BiometricAvailability {
        val biometricManager = BiometricManager.from(activity)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS ->
                BiometricAvailability.Available

            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE ->
                BiometricAvailability.NoHardware

            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE ->
                BiometricAvailability.HardwareUnavailable

            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED ->
                BiometricAvailability.NoneEnrolled

            BiometricManager.BIOMETRIC_ERROR_SECURITY_UPDATE_REQUIRED ->
                BiometricAvailability.SecurityUpdateRequired

            else ->
                BiometricAvailability.Unknown
        }
    }

    /**
     * Authenticate with biometric and decrypt stored session token.
     * The CryptoObject ensures the biometric result is cryptographically bound.
     */
    fun authenticateForDecryption(callback: BiometricCallback) {
        if (canUseBiometric() != BiometricAvailability.Available) {
            callback.onBiometricNotAvailable("Biometric authentication is not available")
            return
        }

        if (!SecureSessionManager.isBiometricEnrolled(activity)) {
            callback.onBiometricFallbackToPassword()
            return
        }

        val cipher = try {
            SecureSessionManager.getDecryptionCipher(activity)
        } catch (e: Exception) {
            // Key invalidated (e.g., new biometric enrolled)
            SecureSessionManager.clearBiometricData(activity)
            callback.onBiometricError(-1, "Biometric data invalidated. Please log in with password.")
            return
        }

        if (cipher == null) {
            callback.onBiometricFallbackToPassword()
            return
        }

        val cryptoObject = BiometricPrompt.CryptoObject(cipher)

        val executor = ContextCompat.getMainExecutor(activity)

        val biometricPrompt = BiometricPrompt(activity, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)

                    val authenticatedCipher = result.cryptoObject?.cipher
                    if (authenticatedCipher == null) {
                        callback.onBiometricError(-1, "Authentication failed: no crypto object")
                        return
                    }

                    // Decrypt the session token using the biometric-authenticated cipher
                    val sessionToken = SecureSessionManager.decryptSessionToken(
                        activity, authenticatedCipher
                    )

                    if (sessionToken != null && SessionValidator.validateSessionToken(sessionToken)) {
                        SessionValidator.restoreSession(sessionToken)
                        callback.onBiometricSuccess(sessionToken)
                    } else {
                        // Token invalid or expired - require password login
                        SecureSessionManager.clearBiometricData(activity)
                        callback.onBiometricError(-1, "Session expired. Please log in with password.")
                    }
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)

                    when (errorCode) {
                        BiometricPrompt.ERROR_NEGATIVE_BUTTON,
                        BiometricPrompt.ERROR_USER_CANCELED ->
                            callback.onBiometricFallbackToPassword()

                        BiometricPrompt.ERROR_LOCKOUT,
                        BiometricPrompt.ERROR_LOCKOUT_PERMANENT ->
                            callback.onBiometricError(errorCode, "Too many attempts. Use password instead.")

                        else ->
                            callback.onBiometricError(errorCode, errString.toString())
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    // Individual attempt failed, prompt remains open for retry
                }
            })

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Login")
            .setSubtitle("Use your fingerprint to sign in")
            .setDescription("Touch the fingerprint sensor to verify your identity")
            .setNegativeButtonText("Use Password")
            .setConfirmationRequired(true)
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
            .build()

        biometricPrompt.authenticate(promptInfo, cryptoObject)
    }

    /**
     * After successful password login, encrypt and store the session token
     * bound to biometric authentication.
     */
    fun enrollBiometricForSession(sessionToken: String, callback: BiometricCallback) {
        if (canUseBiometric() != BiometricAvailability.Available) {
            callback.onBiometricNotAvailable("Biometric not available for enrollment")
            return
        }

        val cipher = try {
            SecureSessionManager.getEncryptionCipher()
        } catch (e: Exception) {
            callback.onBiometricError(-1, "Failed to initialize encryption: ${e.message}")
            return
        }

        val cryptoObject = BiometricPrompt.CryptoObject(cipher)
        val executor = ContextCompat.getMainExecutor(activity)

        val biometricPrompt = BiometricPrompt(activity, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)

                    val authenticatedCipher = result.cryptoObject?.cipher
                    if (authenticatedCipher == null) {
                        callback.onBiometricError(-1, "Enrollment failed: no crypto object")
                        return
                    }

                    // Encrypt and store the session token
                    SecureSessionManager.storeEncryptedSessionToken(
                        activity, authenticatedCipher, sessionToken
                    )

                    callback.onBiometricSuccess(sessionToken)
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    callback.onBiometricError(errorCode, errString.toString())
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                }
            })

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Enable Biometric Login")
            .setSubtitle("Verify your fingerprint to enable quick sign-in")
            .setDescription("Your session will be securely stored and protected by your biometric")
            .setNegativeButtonText("Skip")
            .setConfirmationRequired(true)
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG)
            .build()

        biometricPrompt.authenticate(promptInfo, cryptoObject)
    }

    enum class BiometricAvailability {
        Available,
        NoHardware,
        HardwareUnavailable,
        NoneEnrolled,
        SecurityUpdateRequired,
        Unknown
    }
}

// --- Login Activity ---

class LoginActivity : AppCompatActivity(), BiometricHelper.BiometricCallback {

    private lateinit var biometricHelper: BiometricHelper

    private lateinit var usernameInput: EditText
    private lateinit var passwordInput: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button
    private lateinit var statusText: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        biometricHelper = BiometricHelper(this)

        setupUI()

        // If biometric is enrolled, attempt biometric login automatically
        if (SecureSessionManager.isBiometricEnrolled(this) &&
            biometricHelper.canUseBiometric() == BiometricHelper.BiometricAvailability.Available
        ) {
            statusText.text = "Authenticating with biometric..."
            biometricHelper.authenticateForDecryption(this)
        } else {
            showPasswordUI()
        }
    }

    private fun setupUI() {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
        }

        val titleText = TextView(this).apply {
            text = "Secure Login"
            textSize = 28f
            setPadding(0, 0, 0, 48)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(titleText)

        statusText = TextView(this).apply {
            text = ""
            textSize = 14f
            setPadding(0, 0, 0, 24)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(statusText)

        usernameInput = EditText(this).apply {
            hint = "Username"
            inputType = android.text.InputType.TYPE_CLASS_TEXT
            setPadding(24, 24, 24, 24)
        }
        layout.addView(usernameInput)

        passwordInput = EditText(this).apply {
            hint = "Password (min 6 characters)"
            inputType = android.text.InputType.TYPE_CLASS_TEXT or
                    android.text.InputType.TYPE_TEXT_VARIATION_PASSWORD
            setPadding(24, 24, 24, 24)
        }
        layout.addView(passwordInput)

        loginButton = Button(this).apply {
            text = "Sign In with Password"
            setOnClickListener { performPasswordLogin() }
        }
        layout.addView(loginButton)

        biometricButton = Button(this).apply {
            text = "Sign In with Fingerprint"
            setOnClickListener {
                biometricHelper.authenticateForDecryption(this@LoginActivity)
            }
            visibility = android.view.View.GONE
        }
        layout.addView(biometricButton)

        val logoutBiometricButton = Button(this).apply {
            text = "Clear Biometric Data"
            setOnClickListener {
                SecureSessionManager.clearBiometricData(this@LoginActivity)
                SessionValidator.logout()
                Toast.makeText(this@LoginActivity, "Biometric data cleared", Toast.LENGTH_SHORT).show()
                showPasswordUI()
            }
        }
        layout.addView(logoutBiometricButton)

        setContentView(layout)
    }

    private fun showPasswordUI() {
        usernameInput.visibility = android.view.View.VISIBLE
        passwordInput.visibility = android.view.View.VISIBLE
        loginButton.visibility = android.view.View.VISIBLE

        val hasBiometricEnrolled = SecureSessionManager.isBiometricEnrolled(this) &&
                biometricHelper.canUseBiometric() == BiometricHelper.BiometricAvailability.Available

        biometricButton.visibility = if (hasBiometricEnrolled) {
            android.view.View.VISIBLE
        } else {
            android.view.View.GONE
        }

        statusText.text = if (hasBiometricEnrolled) {
            "Sign in with password or use fingerprint"
        } else {
            "Sign in with your credentials"
        }
    }

    private fun performPasswordLogin() {
        val username = usernameInput.text.toString().trim()
        val password = passwordInput.text.toString()

        if (username.isBlank()) {
            usernameInput.error = "Username required"
            return
        }
        if (password.length < 6) {
            passwordInput.error = "Password must be at least 6 characters"
            return
        }

        statusText.text = "Signing in..."
        loginButton.isEnabled = false

        // Perform actual credential validation
        when (val result = SessionValidator.performLogin(username, password)) {
            is SessionValidator.LoginResult.Success -> {
                val sessionToken = result.sessionToken

                // Offer biometric enrollment if available and not already enrolled
                if (biometricHelper.canUseBiometric() == BiometricHelper.BiometricAvailability.Available) {
                    offerBiometricEnrollment(sessionToken)
                } else {
                    navigateToMain()
                }
            }

            is SessionValidator.LoginResult.Failure -> {
                statusText.text = "Login failed: ${result.message}"
                loginButton.isEnabled = true
            }
        }
    }

    private fun offerBiometricEnrollment(sessionToken: String) {
        val builder = android.app.AlertDialog.Builder(this)
        builder.setTitle("Enable Fingerprint Login?")
        builder.setMessage(
            "Would you like to use your fingerprint for faster sign-in next time? " +
                    "Your session will be securely encrypted and protected by your biometric."
        )
        builder.setPositiveButton("Enable") { _, _ ->
            biometricHelper.enrollBiometricForSession(sessionToken, object : BiometricHelper.BiometricCallback {
                override fun onBiometricSuccess(sessionToken: String) {
                    Toast.makeText(
                        this@LoginActivity,
                        "Fingerprint login enabled!",
                        Toast.LENGTH_SHORT
                    ).show()
                    navigateToMain()
                }

                override fun onBiometricError(errorCode: Int, errorMessage: String) {
                    Toast.makeText(
                        this@LoginActivity,
                        "Biometric enrollment skipped: $errorMessage",
                        Toast.LENGTH_SHORT
                    ).show()
                    navigateToMain()
                }

                override fun onBiometricFallbackToPassword() {
                    navigateToMain()
                }

                override fun onBiometricNotAvailable(reason: String) {
                    navigateToMain()
                }
            })
        }
        builder.setNegativeButton("Not Now") { _, _ ->
            navigateToMain()
        }
        builder.setCancelable(false)
        builder.show()
    }

    // --- BiometricCallback implementation ---

    override fun onBiometricSuccess(sessionToken: String) {
        // Session token was decrypted and validated successfully
        Toast.makeText(this, "Biometric authentication successful!", Toast.LENGTH_SHORT).show()
        navigateToMain()
    }

    override fun onBiometricError(errorCode: Int, errorMessage: String) {
        statusText.text = errorMessage
        showPasswordUI()
        Toast.makeText(this, errorMessage, Toast.LENGTH_LONG).show()
    }

    override fun onBiometricFallbackToPassword() {
        statusText.text = "Please sign in with your password"
        showPasswordUI()
    }

    override fun onBiometricNotAvailable(reason: String) {
        statusText.text = reason
        showPasswordUI()
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}

// --- Main Activity (Protected Screen) ---

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Verify we have a valid session
        val activeToken = SessionValidator.getActiveToken()
        if (activeToken == null || !SessionValidator.validateSessionToken(activeToken)) {
            // No valid session - redirect to login
            redirectToLogin()
            return
        }

        setupUI()
    }

    private fun setupUI() {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER
        }

        val welcomeText = TextView(this).apply {
            text = "Welcome!"
            textSize = 32f
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 24)
        }
        layout.addView(welcomeText)

        val secureText = TextView(this).apply {
            text = "You are securely authenticated.\n\n" +
                    "Session: ${SessionValidator.getActiveToken()?.take(30)}..."
            textSize = 14f
            gravity = android.view.Gravity.CENTER
            setPadding(0, 0, 0, 48)
        }
        layout.addView(secureText)

        val logoutButton = Button(this).apply {
            text = "Logout"
            setOnClickListener {
                SessionValidator.logout()
                redirectToLogin()
            }
        }
        layout.addView(logoutButton)

        val fullLogoutButton = Button(this).apply {
            text = "Logout & Clear Biometric"
            setOnClickListener {
                SessionValidator.logout()
                SecureSessionManager.clearBiometricData(this@MainActivity)
                redirectToLogin()
            }
        }
        layout.addView(fullLogoutButton)

        setContentView(layout)
    }

    private fun redirectToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}